+function parseConfig(content: string, path: string): Record<string, unknown> {
+  if (path.endsWith(".json")) return JSON.parse(content);
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index < 1) throw new TypeError(`Invalid RC entry "${line}".`);
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) throw new TypeError(`Unterminated quoted value for "${key}".`);
+      value = value.slice(1, -1);
+    } else if (value === "true") value = true as unknown as string;
+    else if (value === "false") value = false as unknown as string;
+    else if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) value = Number(value) as unknown as string;
+    values[kebabToCamelCase(key)] = value;
+  }
+  return values;
+}
+
+function flattenConfig(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${kebabToCamelCase(key)}` : kebabToCamelCase(key);
+    if (isPlainObject(child)) Object.assign(result, flattenConfig(child, name));
+    else result[name] = child;
+  }
+  return result;
+}
+
+function kebabToCamelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  if (!value || typeof value !== "object" || Array.isArray(value)) return false;
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === Object.prototype || prototype === null;
+}
