import { test } from "@cliffy/internal/testing/test";
import { assertEquals, assertInstanceOf } from "@std/assert";
import { Command } from "../../command.ts";
import { ConfigParseError, ConfigValidationError } from "../../config/mod.ts";

test("command - config - json values, precedence, and getters", async () => {
  const dir = await Deno.makeTempDir();
  try {
    const path = `${dir}/app.json`;
    await Deno.writeTextFile(
      path,
      JSON.stringify({
        port: 0,
        enabled: false,
        "log-level": "debug",
        tags: ["one", "two"],
        nested: { value: "ignored" },
      }),
    );
    const cmd = new Command().throwErrors().config({
      name: "app",
      searchPaths: [dir],
    })
      .option("--port <port:number>", "")
      .option("--enabled", "")
      .option("--log-level <level>", "")
      .option("--tags <tag>", "", { collect: true });
    const result = await cmd.parse(["--port", "2"]);
    assertEquals(result.options as unknown, {
      port: 2,
      enabled: false,
      logLevel: "debug",
      tags: ["one", "two"],
    });
    assertEquals(cmd.getConfigPath(), path);
    assertEquals(cmd.getConfigValues().port, 0);
  } finally {
    await Deno.remove(dir, { recursive: true });
  }
});

test("command - config - rc parser and errors", async () => {
  const dir = await Deno.makeTempDir();
  try {
    await Deno.writeTextFile(
      `${dir}/.apprc`,
      '# comment\ncount=0\nenabled=false\nlabel="hello world"\n',
    );
    const cmd = new Command().throwErrors().config({
      name: "app",
      searchPaths: [dir],
    })
      .option("--count <count:number>", "")
      .option("--enabled", "")
      .option("--label <label>", "");
    assertEquals((await cmd.parse()).options as unknown, {
      count: 0,
      enabled: false,
      label: "hello world",
    });

    await Deno.writeTextFile(`${dir}/app.json`, "{");
    await assertInstanceOf(
