    );
    await Deno.remove(`${dir}/app.json`);
    await Deno.writeTextFile(`${dir}/.apprc`, "enabled=nope");
    await assertInstanceOf(
      new Command().throwErrors().config({ name: "app", searchPaths: [dir] })
        .option("--enabled", "").parse(),
      ConfigValidationError,
    );
  } finally {
    await Deno.remove(dir, { recursive: true });
  }
});

